const input = $input.first().json;
const action = input.action || 'run_command';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

// --- Load Open Terminal credentials (url + api key) ---
let creds = {};
try {
  const rows = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.open-terminal&select=cred_key,cred_value',
    headers: pgHeaders
  });
  for (const c of (rows || [])) creds[c.cred_key] = c.cred_value;
} catch (e) {
  return [{ json: { error: 'Could not load credentials: ' + e.message } }];
}

let baseUrl = creds.terminal_url;
const apiKey = creds.terminal_api_key;
if (!baseUrl) {
  return [{ json: { error: 'Open Terminal URL not configured. Set terminal_url (e.g. http://172.17.0.1:8000) via the credential form.' } }];
}
baseUrl = String(baseUrl).replace(/\/+$/, '');

const otHeaders = { 'Content-Type': 'application/json' };
if (apiKey) otHeaders['Authorization'] = 'Bearer ' + apiKey;

const TRUNC = 6000;
function clip(s) {
  s = String(s == null ? '' : s);
  if (s.length > TRUNC) return s.substring(0, TRUNC) + '\n\n... (truncated, ' + s.length + ' chars total)';
  return s;
}
// Open Terminal returns output as [{type:'stdout'|'stderr'|'output', data:'...'}]
function fmtOutput(o) {
  if (o == null) return '';
  if (typeof o === 'string') return o;
  if (Array.isArray(o)) return o.map(e => (e == null) ? '' : (typeof e === 'string' ? e : (e.data != null ? e.data : ''))).join('');
  return '';
}
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

try {
  if (action === 'run_command') {
    const command = String(input.command || '').trim();
    if (!command) {
      return [{ json: { error: 'Parameter "command" is required (e.g. "ls -la", "echo hello").' } }];
    }

    // --- Soft guardrail: warn on known-destructive patterns unless confirmed ---
    const confirm = input.confirm === true || input.confirm === 'true' || input.confirm === 'yes' || input.confirm === '1';
    const DANGER = [
      /\brm\s+(-\S+\s+)*-\S*[rf]\S*\s+(\/|~|\$HOME|\*)(\s|$|\/)/i,
      /\brm\s+-\S*r\S*f|\brm\s+-\S*f\S*r/i,
      /\bmkfs\b/i,
      /\bdd\b[^\n]*\bof=\/dev\//i,
      />\s*\/dev\/(sd|nvme|hd|mmcblk|vd)/i,
      /\b(shutdown|reboot|halt|poweroff)\b/i,
      /\binit\s+0\b/i,
      /:\(\)\s*\{\s*:\s*\|\s*:\s*&\s*\}\s*;\s*:/,
      /\bchmod\s+-R\s+0{3}\s+\//i,
      /\bchown\s+-R\b[^\n]*\s+\/\s*$/i,
      /\bgit\s+(reset\s+--hard|clean\s+-\S*f)/i,
      /\b(truncate|shred)\b[^\n]*\/dev\//i
    ];
    if (DANGER.some(re => re.test(command)) && !confirm) {
      return [{ json: { result: '⚠️ This command looks potentially destructive and was NOT executed:\n  ' + command + '\n\nIf you are sure, call run_command again with confirm=true.' } }];
    }

    let totalSec = parseInt(input.timeout, 10);
    if (!totalSec || totalSec < 1) totalSec = 60;
    if (totalSec > 180) totalSec = 180;
    const firstWait = Math.min(totalSec, 30);

    const body = { command };
    if (input.cwd) body.cwd = String(input.cwd);

    let start;
    try {
      start = await helpers.httpRequest({
        method: 'POST',
        url: baseUrl + '/execute?wait=' + firstWait,
        headers: otHeaders,
        body: JSON.stringify(body)
      });
    } catch (e) {
      return [{ json: { error: 'Could not reach Open Terminal at ' + baseUrl + ': ' + e.message } }];
    }

    const procId = start.id;
    const outParts = [fmtOutput(start.output)];
    let off = start.next_offset || 0;
    let status = start.status;
    let exitCode = start.exit_code;

    const deadline = Date.now() + totalSec * 1000;
    while (status === 'running' && Date.now() < deadline) {
      await sleep(1200);
      let st;
      try {
        st = await helpers.httpRequest({
          method: 'GET',
          url: baseUrl + '/execute/' + encodeURIComponent(procId) + '/status?wait=10&offset=' + off,
          headers: otHeaders
        });
      } catch (e) { break; }
      const part = fmtOutput(st.output);
      if (part) outParts.push(part);
      off = (st.next_offset != null) ? st.next_offset : off;
      status = st.status;
      exitCode = st.exit_code;
    }

    const outText = clip(outParts.join('').trim());
    if (status === 'running') {
      return [{ json: { result: 'Command still running after ' + totalSec + 's (process_id: ' + procId + ').\n\nOutput so far:\n' + (outText || '(none yet)') + '\n\nIt keeps running on the server. Use send_input with process_id="' + procId + '" to interact, or run it again with a higher timeout.' } }];
    }
    return [{ json: { result: 'Exit code: ' + (exitCode == null ? 'unknown' : exitCode) + ' (process_id: ' + procId + ')\n\nOutput:\n' + (outText || '(no output)') } }];

  } else if (action === 'send_input') {
    const procId = String(input.process_id || '').trim();
    if (!procId) return [{ json: { error: 'Parameter "process_id" is required (from a run_command that is still running).' } }];
    if (input.text == null || input.text === '') return [{ json: { error: 'Parameter "text" is required (text for stdin; use \\n for Enter, \\x03 for Ctrl-C).' } }];
    try {
      await helpers.httpRequest({
        method: 'POST',
        url: baseUrl + '/execute/' + encodeURIComponent(procId) + '/input',
        headers: otHeaders,
        body: JSON.stringify({ input: String(input.text) })
      });
    } catch (e) {
      return [{ json: { error: 'send_input failed (the process may have already exited): ' + e.message } }];
    }
    await sleep(1500);
    let outText = '', status = 'running', exitCode = null;
    try {
      const st = await helpers.httpRequest({
        method: 'GET',
        url: baseUrl + '/execute/' + encodeURIComponent(procId) + '/status?wait=5&offset=0',
        headers: otHeaders
      });
      outText = clip(fmtOutput(st.output).trim());
      status = st.status;
      exitCode = st.exit_code;
    } catch (e) { /* ignore */ }
    return [{ json: { result: 'Input sent to ' + procId + '. Status: ' + status + (exitCode != null ? ' (exit ' + exitCode + ')' : '') + '\n\nOutput:\n' + (outText || '(no new output)') } }];

  } else if (action === 'read_file') {
    const path = String(input.path || '').trim();
    if (!path) return [{ json: { error: 'Parameter "path" is required.' } }];
    let q = '/files/read?path=' + encodeURIComponent(path);
    if (input.start_line) q += '&start_line=' + encodeURIComponent(input.start_line);
    if (input.end_line) q += '&end_line=' + encodeURIComponent(input.end_line);
    let resp;
    try {
      resp = await helpers.httpRequest({ method: 'GET', url: baseUrl + q, headers: otHeaders });
    } catch (e) {
      return [{ json: { error: 'read_file failed: ' + e.message + ' (binary files cannot be read as text).' } }];
    }
    if (resp && typeof resp === 'object' && resp.content != null) {
      return [{ json: { result: 'File: ' + (resp.path || path) + (resp.total_lines != null ? ' (' + resp.total_lines + ' lines)' : '') + '\n\n' + clip(resp.content) } }];
    }
    return [{ json: { result: 'Read ' + path + ' but it returned non-text content (likely binary).' } }];

  } else if (action === 'write_file') {
    const path = String(input.path || '').trim();
    if (!path) return [{ json: { error: 'Parameter "path" is required.' } }];
    if (input.content == null) return [{ json: { error: 'Parameter "content" is required (text to write).' } }];
    let resp;
    try {
      resp = await helpers.httpRequest({
        method: 'POST',
        url: baseUrl + '/files/write',
        headers: otHeaders,
        body: JSON.stringify({ path: path, content: String(input.content) })
      });
    } catch (e) {
      return [{ json: { error: 'write_file failed: ' + e.message } }];
    }
    return [{ json: { result: 'Wrote ' + (resp && resp.size != null ? resp.size + ' bytes to ' : '') + ((resp && resp.path) || path) } }];

  } else if (action === 'list_files') {
    const dir = String(input.directory || '.').trim() || '.';
    let resp;
    try {
      resp = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/files/list?directory=' + encodeURIComponent(dir), headers: otHeaders });
    } catch (e) {
      return [{ json: { error: 'list_files failed: ' + e.message } }];
    }
    const entries = (resp && resp.entries) || [];
    const lines = entries.map(e => {
      if (typeof e === 'string') return e;
      const name = e.name || e.path || JSON.stringify(e);
      const type = e.type || (e.is_dir ? 'directory' : 'file');
      const size = (e.size != null) ? ' (' + e.size + ' B)' : '';
      return ((type === 'directory' || type === 'dir') ? '[d] ' : '[f] ') + name + size;
    });
    return [{ json: { result: 'Directory: ' + ((resp && resp.dir) || dir) + '\n' + clip(lines.join('\n') || '(empty)') } }];

  } else if (action === 'check_terminal') {
    let health;
    try {
      health = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/health', headers: otHeaders });
    } catch (e) {
      return [{ json: { error: 'Open Terminal not reachable at ' + baseUrl + ': ' + e.message } }];
    }
    let config = null;
    try {
      config = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/api/config', headers: otHeaders });
    } catch (e) { /* config is optional */ }
    return [{ json: { result: 'Open Terminal at ' + baseUrl + ' is reachable. Health: ' + JSON.stringify(health) + (config ? '\nFeatures: ' + JSON.stringify(config.features || config) : '') } }];

  } else {
    return [{ json: { error: 'Unknown action: "' + action + '". Available: run_command, send_input, read_file, write_file, list_files, check_terminal.' } }];
  }
} catch (e) {
  return [{ json: { error: 'open-terminal error: ' + (e.message || String(e)) } }];
}
